module RefModule(
    input A,
    input B,
    output X
);// Define and instantiate a basic logical AND operation
    wire and_output;

  wire temp1_A = A;
  wire temp2_B = B;
  assign and_output = temp1_A & temp2_B;

    // Drive the output X with the AND operation result
    assign X = and_output;

endmodule
